// Google News RSS queries aimed at Texas LEGISLATIVE activity the LegiScan flow
// can't see: local ordinances/moratoriums, and new state bills before they index.
const DQ = String.fromCharCode(34);
const QUERIES = [
  'Texas ' + DQ + 'data center' + DQ + ' (bill OR legislation OR ordinance OR moratorium)',
  'Texas (groundwater OR water) (bill OR legislation OR ' + DQ + 'conservation district' + DQ + ')',
  'Texas (county OR city) ' + DQ + 'data center' + DQ + ' (ordinance OR moratorium OR zoning OR pause)',
  'Texas legislature (data center OR ' + DQ + 'large load' + DQ + ' OR eminent domain) (prefiled OR 2027)'
];
return QUERIES.map(q => ({ json: { url: 'https://news.google.com/rss/search?q=' + encodeURIComponent(q) + '&hl=en-US&gl=US&ceid=US:en', query: q } }));

// Collect RSS articles into one numbered text block + a lookup list so the
// filter sees all headlines at once and cites each by index (real link mapped
// back later by sourceIndex — no URL hallucination).
const items = $input.all();
const headlines = [];
for (const it of items) {
  const j = it.json || {};
  const title = String(j.title || '').trim();
  if (!title) continue;
  const url = String(j.link || j.guid || '').trim();
  const snippet = String(j.contentSnippet || j.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 280);
  let source = String(j.creator || '').trim();
  if (!source && title.includes(' - ')) source = title.split(' - ').pop().trim();
  headlines.push({ i: headlines.length, title, snippet, url, source });
}
const text = headlines.map(h => h.i + ') ' + h.title + (h.snippet ? ' \u2014 ' + h.snippet : '')).join('\n');
return [{ json: { headlines, text } }];

