// Turn the filtered leads into a single email digest. Maps each lead back to its
// real source URL by sourceIndex. Writes NO tracker entries — leads only.
const resp = $json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text || ''; } catch (e) { text = ''; }
text = text.trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
let leads = [];
try { leads = JSON.parse(text); } catch (e) {
  const m = text.match(/\[([\s\S]*)\]/);
  if (m) { try { leads = JSON.parse(m[0]); } catch (e2) { leads = []; } }
}
if (!Array.isArray(leads)) leads = [];
const headlines = $('Collect headlines').first().json.headlines || [];

const rows = leads.map(l => {
  const src = headlines[l.sourceIndex] || {};
  const url = (src.url && /^https?:\/\//i.test(src.url)) ? src.url : '';
  if (!url) return '';
  const kind = String(l.kind || 'lead');
  return '<li style="margin-bottom:12px"><strong>[' + kind + ']</strong> ' + (l.headline || src.title || '') + '<br><span style="color:#555">' + (l.why || '') + '</span><br><a href="' + url + '">' + (src.source || 'source') + ' &raquo;</a></li>';
}).filter(Boolean);

const date = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
let html;
if (rows.length === 0) {
  html = '<h2>Legislation radar \u2014 ' + date + '</h2><p>No new Texas legislative leads (bills, statutes, or local ordinances) this week.</p>';
} else {
  html = '<h2>Legislation radar \u2014 ' + date + '</h2><p>' + rows.length + ' possible development(s). These are LEADS only \u2014 curate a verified /legislation entry from any that check out (local ordinances are not in LegiScan).</p><ul style="padding-left:18px">' + rows.join('') + '</ul>';
}
return [{ json: { emailBodyHtml: html, leadCount: rows.length } }];
